import{_ as e,o as t,c as i,ag as l}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"日志与通知","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/logs-notifications.md","filePath":"guide/help/logs-notifications.md","lastUpdated":1780491682000}'),s={name:"guide/help/logs-notifications.md"};function o(d,a,r,p,n,h){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="日志与通知" tabindex="-1">日志与通知 <a class="header-anchor" href="#日志与通知" aria-label="Permalink to &quot;日志与通知&quot;">​</a></h1><p>日志和通知用于回答两个问题：</p><ul><li>任务现在跑到哪里了？</li><li>为什么没有按预期转存、入库或发信？</li></ul><h2 id="系统日志" tabindex="-1">系统日志 <a class="header-anchor" href="#系统日志" aria-label="Permalink to &quot;系统日志&quot;">​</a></h2><p>入口：<code>系统日志</code></p><p>系统日志页面展示最近日志窗口，适合快速查看当前问题。完整原始文件在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/log/app.log</span></span></code></pre></div><p>如果日志很多，页面不会一次性展示全部内容，避免浏览器卡顿。需要完整排查时，下载文件或直接查看宿主机上的日志文件。</p><h2 id="docker-日志" tabindex="-1">Docker 日志 <a class="header-anchor" href="#docker-日志" aria-label="Permalink to &quot;Docker 日志&quot;">​</a></h2><p>Docker Compose 示例同时保留 Docker 日志：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pansave</span></span></code></pre></div><p>应用文件日志和 Docker 日志默认都按 <code>10m / 7</code> 轮转。</p><h2 id="系统通知" tabindex="-1">系统通知 <a class="header-anchor" href="#系统通知" aria-label="Permalink to &quot;系统通知&quot;">​</a></h2><p>系统通知主要提醒这些情况：</p><ul><li>频道扫描或转存任务完成</li><li>任务部分失败</li><li>转存目录缺失或失效</li><li>网盘容量不足</li><li>账号登录态失效</li><li>管理员登录连续多次失败</li></ul><p>系统会优先通过内置机器人发送 Telegram 提醒。如果配置了邮箱并启用系统邮件通知，也会同步发管理员邮件。</p><h2 id="邮件通知" tabindex="-1">邮件通知 <a class="header-anchor" href="#邮件通知" aria-label="Permalink to &quot;邮件通知&quot;">​</a></h2><p>入口：<code>系统配置 / 邮箱配置</code></p><p>邮件通知分两类：</p><table tabindex="0"><thead><tr><th>类型</th><th>接收者</th></tr></thead><tbody><tr><td>系统通知邮件</td><td>管理员邮箱。</td></tr><tr><td>豆瓣求片用户邮件</td><td>求片用户自己配置的邮箱。</td></tr></tbody></table><p>免打扰只影响邮件，不影响 Telegram 机器人提醒。</p><h2 id="排查通知没有发出" tabindex="-1">排查通知没有发出 <a class="header-anchor" href="#排查通知没有发出" aria-label="Permalink to &quot;排查通知没有发出&quot;">​</a></h2><p>按这个顺序检查：</p><ol><li>邮箱配置是否完整，测试发信是否成功。</li><li>邮件通知总开关是否开启。</li><li>是否处于免打扰时间段。</li><li>内置机器人是否配置，系统 Telegram 用户 ID 是否正确。</li><li>系统日志里是否有 SMTP、机器人或网络错误。</li></ol><p>如果 Telegram 机器人发送失败，系统会记录失败原因，但不会因此修改原业务状态。</p>',25)])])}const g=e(s,[["render",o]]);export{u as __pageData,g as default};
